"""Practice analysis models shared by practice/result APIs."""

from enum import Enum
from typing import Optional

from pydantic import BaseModel, Field

from app.models.marked_token import MarkedToken


class AnalysisState(str, Enum):
    """App-facing analysis states for the latest learner attempt."""

    loading = "loading"
    info = "info"
    perfect = "perfect"
    unavailable = "unavailable"


class TutorReviewResult(BaseModel):
    """Review payload generated by the backend for one learner attempt."""

    state: AnalysisState
    marked_tokens: list[MarkedToken] = Field(default_factory=list)
    feedback_text: Optional[str] = None
